+    fn number_keys_force_tier() {
+        let mut hud = PerformanceHud::new();
+        assert!(hud.forced_tier.is_none());
+
+        hud.update(&press(KeyCode::Char('1')));
+        assert_eq!(hud.forced_tier, Some(DegradationTier::Full));
