+
+        hud.update(&press(KeyCode::Char('3')));
+        assert_eq!(hud.forced_tier, Some(DegradationTier::Minimal));
+
+        hud.update(&press(KeyCode::Char('4')));
+        assert_eq!(hud.forced_tier, Some(DegradationTier::Safety));
